import{_ as a,o as s,c as i,ag as e}from"./chunks/framework.C9sp7nFj.js";const k=JSON.parse('{"title":"模型与价格","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pricing.md","filePath":"guide/pricing.md","lastUpdated":null}'),r={name:"guide/pricing.md"};function n(o,t,l,d,p,h){return s(),i("div",null,[...t[0]||(t[0]=[e(`<h1 id="模型与价格" tabindex="-1">模型与价格 <a class="header-anchor" href="#模型与价格" aria-label="Permalink to &quot;模型与价格&quot;">​</a></h1><h2 id="如何查看可用模型" tabindex="-1">如何查看可用模型 <a class="header-anchor" href="#如何查看可用模型" aria-label="Permalink to &quot;如何查看可用模型&quot;">​</a></h2><p>登录 <a href="https://api.kkkk24juastin.asia" target="_blank" rel="noreferrer">使用站点</a> 后，你可以在以下位置查看可用模型：</p><ol><li><strong>控制台首页</strong>：通常会展示支持的模型列表</li><li><strong>API 接口</strong>：通过调用 <code>/v1/models</code> 接口获取完整的模型列表</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.kkkk24juastin.asia/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-你的API密钥&quot;</span></span></code></pre></div><h2 id="如何查看价格" tabindex="-1">如何查看价格 <a class="header-anchor" href="#如何查看价格" aria-label="Permalink to &quot;如何查看价格&quot;">​</a></h2><p>登录使用站点后，进入「价格」或「模型价格」页面，可以查看每个模型的详细定价信息。</p><p>不同模型的价格差异较大，建议根据实际需求选择合适的模型类型：</p><table tabindex="0"><thead><tr><th>模型类型</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>旗舰模型</strong></td><td>综合能力最强</td><td>复杂推理、深度分析、高质量写作</td></tr><tr><td><strong>轻量模型</strong></td><td>速度快、价格低</td><td>简单问答、快速任务、日常对话</td></tr><tr><td><strong>长文本模型</strong></td><td>上下文窗口大</td><td>文档分析、长文总结、代码审查</td></tr><tr><td><strong>多模态模型</strong></td><td>支持图文输入</td><td>图片理解、视觉分析、图文任务</td></tr><tr><td><strong>高性价比模型</strong></td><td>性能与价格平衡</td><td>中文场景、日常使用、批量调用</td></tr></tbody></table><p>具体支持哪些模型以及对应价格，请在使用站点的「价格」页面查看。</p><h2 id="token-怎么计费" tabindex="-1">Token 怎么计费 <a class="header-anchor" href="#token-怎么计费" aria-label="Permalink to &quot;Token 怎么计费&quot;">​</a></h2><p>AI 模型按 <strong>Token</strong> 计费。Token 是文本的基本单位，大致理解：</p><ul><li><strong>1 个英文单词</strong> ≈ 1 个 Token</li><li><strong>1 个中文字</strong> ≈ 1.5-2 个 Token</li><li><strong>1000 个 Token</strong> ≈ 750 个英文单词 或 500 个中文字</li></ul><p>每次 API 调用的费用 = <strong>输入 Token 数 × 输入价格 + 输出 Token 数 × 输出价格</strong></p><p>举个例子：你发了一条 100 Token 的消息，AI 回复了 200 Token，那么这次调用消耗了 300 Token。</p><div class="tip custom-block"><p class="custom-block-title">节省 Token 的技巧</p><ul><li>提问时尽量简洁明了</li><li>避免发送过长的上下文</li><li>对于简单任务，使用轻量模型，价格更便宜</li><li>合理设置 <code>max_tokens</code> 参数限制输出长度</li></ul></div><h2 id="为什么不同模型扣费不一样" tabindex="-1">为什么不同模型扣费不一样 <a class="header-anchor" href="#为什么不同模型扣费不一样" aria-label="Permalink to &quot;为什么不同模型扣费不一样&quot;">​</a></h2><p>不同模型的定价不同，主要原因：</p><ol><li><strong>模型能力不同</strong>：更强大的模型训练成本更高，价格也更贵</li><li><strong>输入/输出价格不同</strong>：大多数模型的输出价格高于输入价格（因为生成比回忆更消耗算力）</li><li><strong>上下文窗口不同</strong>：支持更长上下文的模型通常价格更高</li></ol><p>建议根据任务类型选择模型：</p><ul><li><strong>简单问答、翻译</strong>：使用轻量模型，价格便宜</li><li><strong>复杂推理、编程</strong>：使用旗舰模型，效果更好</li><li><strong>长文档分析</strong>：选择支持长上下文的模型</li></ul><p>具体模型列表和价格，请登录 <a href="https://api.kkkk24juastin.asia" target="_blank" rel="noreferrer">使用站点</a> 查看「价格」页面。</p>`,22)])])}const c=a(r,[["render",n]]);export{k as __pageData,c as default};
